235	// Simple version of "llama_apply_chat_template" that only works with strings
236	// This function uses heuristic checks to determine commonly used template. It is not a jinja parser.
237	int32_t llm_chat_apply_template(
238	    llm_chat_template tmpl,
239	    const std::vector<const llama_chat_message *> & chat,
240	    std::string & dest, bool add_ass) {
241	    // Taken from the research: https://github.com/ggml-org/llama.cpp/issues/5527
242	    std::stringstream ss;
243	    if (tmpl == LLM_CHAT_TEMPLATE_CHATML) {
244	        // chatml template
245	        for (auto message : chat) {
246	            ss << "<|im_start|>" << message->role << "\n" << message->content << "<|im_end|>\n";
247	        }
248	        if (add_ass) {
249	            ss << "<|im_start|>assistant\n";
250	        }
251	    } else if (tmpl == LLM_CHAT_TEMPLATE_MISTRAL_V7 || tmpl == LLM_CHAT_TEMPLATE_MISTRAL_V7_TEKKEN) {
252	        // Official mistral 'v7' template
253	        // See: https://huggingface.co/mistralai/Mistral-Large-Instruct-2411#basic-instruct-template-v7
254	        //      https://huggingface.co/mistralai/Mistral-Small-3.1-24B-Instruct-2503#basic-instruct-template-v7-tekken
255	        const char * trailing_space = tmpl == LLM_CHAT_TEMPLATE_MISTRAL_V7 ? " " : "";
256	        for (auto message : chat) {
257	            std::string role(message->role);
258	            std::string content(message->content);
259	            if (role == "system") {
260	                ss << "[SYSTEM_PROMPT]" << trailing_space << content << "[/SYSTEM_PROMPT]";
261	            } else if (role == "user") {
262	                ss << "[INST]" << trailing_space << content << "[/INST]";
263	            } else {
264	                ss << trailing_space << content << "</s>";
265	            }
266	        }
267	    } else if (tmpl == LLM_CHAT_TEMPLATE_MISTRAL_V1
268	            || tmpl == LLM_CHAT_TEMPLATE_MISTRAL_V3
269	            || tmpl == LLM_CHAT_TEMPLATE_MISTRAL_V3_TEKKEN) {
270	        // See: https://github.com/mistralai/cookbook/blob/main/concept-deep-dive/tokenization/chat_templates.md
271	        // See: https://github.com/mistralai/cookbook/blob/main/concept-deep-dive/tokenization/templates.md
272	        std::string leading_space = tmpl == LLM_CHAT_TEMPLATE_MISTRAL_V1 ? " " : "";
273	        std::string trailing_space = tmpl == LLM_CHAT_TEMPLATE_MISTRAL_V3_TEKKEN ? "" : " ";
274	        bool trim_assistant_message = tmpl == LLM_CHAT_TEMPLATE_MISTRAL_V3;
275	        bool is_inside_turn = false;
276	        for (auto message : chat) {
277	            if (!is_inside_turn) {
278	                ss << leading_space << "[INST]" << trailing_space;
279	                is_inside_turn = true;
280	            }
281	            std::string role(message->role);
282	            std::string content(message->content);
283	            if (role == "system") {
284	                ss << content << "\n\n";
285	            } else if (role == "user") {
286	                ss << content << leading_space << "[/INST]";
287	            } else {
288	                ss << trailing_space << (trim_assistant_message ? trim(content) : content) << "</s>";
289	                is_inside_turn = false;
290	            }
291	        }
292	    } else if (
293	            tmpl == LLM_CHAT_TEMPLATE_LLAMA_2
294	            || tmpl == LLM_CHAT_TEMPLATE_LLAMA_2_SYS
295	            || tmpl == LLM_CHAT_TEMPLATE_LLAMA_2_SYS_BOS
296	            || tmpl == LLM_CHAT_TEMPLATE_LLAMA_2_SYS_STRIP) {
297	        // llama2 template and its variants
298	        // [variant] support system message
299	        // See: https://huggingface.co/blog/llama2#how-to-prompt-llama-2
300	        bool support_system_message = tmpl != LLM_CHAT_TEMPLATE_LLAMA_2;
301	        // [variant] add BOS inside history
302	        bool add_bos_inside_history = tmpl == LLM_CHAT_TEMPLATE_LLAMA_2_SYS_BOS;
303	        // [variant] trim spaces from the input message
304	        bool strip_message = tmpl == LLM_CHAT_TEMPLATE_LLAMA_2_SYS_STRIP;
305	        // construct the prompt
306	        bool is_inside_turn = true; // skip BOS at the beginning
307	        ss << "[INST] ";
308	        for (auto message : chat) {
309	            std::string content = strip_message ? trim(message->content) : message->content;
310	            std::string role(message->role);
311	            if (!is_inside_turn) {
312	                is_inside_turn = true;
313	                ss << (add_bos_inside_history ? "<s>[INST] " : "[INST] ");
314	            }
315	            if (role == "system") {
316	                if (support_system_message) {
317	                    ss << "<<SYS>>\n" << content << "\n<</SYS>>\n\n";
318	                } else {
319	                    // if the model does not support system message, we still include it in the first message, but without <<SYS>>
320	                    ss << content << "\n";
321	                }
322	            } else if (role == "user") {
323	                ss << content << " [/INST]";
324	            } else {
325	                ss << content << "</s>";
326	                is_inside_turn = false;
327	            }
328	        }
329	    } else if (tmpl == LLM_CHAT_TEMPLATE_PHI_3) {
330	        // Phi 3
331	        for (auto message : chat) {
332	            std::string role(message->role);
333	            ss << "<|" << role << "|>\n" << message->content << "<|end|>\n";
334	        }
335	        if (add_ass) {
